// Preparar promoción — cierra el loop: filas de 'Referentes propuestos' con estado=aprobado se
// convierten en Referentes (activo) y se marcan promovido. Máx 10 por corrida (batch Airtable).
const recs = $('Leer Propuestos').all().flatMap(it => (it.json && it.json.records) || []);
const aprobados = recs.filter(r => String(((r.fields || {}).estado) || '') === 'aprobado').slice(0, 10);
const hoy = new Date().toISOString().slice(0, 10);
const crear = aprobados.map(r => { const f = r.fields || {}; return { fields: {
  handle: String(f.handle || '').trim(),
  plataforma: f.plataforma || 'instagram',
  proyecto: Array.isArray(f.proyecto) ? f.proyecto : [],
  activo: true,
  notas: 'Promovido por descubrimiento ' + hoy + (f.afinidad != null ? ' (afinidad ' + f.afinidad + ')' : '') + (f.razon ? ': ' + String(f.razon).slice(0, 300) : '')
} }; });
const marcar = aprobados.map(r => ({ id: r.id, fields: { estado: 'promovido' } }));
if (crear.length) console.log('[Descubrimiento] promoviendo ' + crear.length + ' referente(s): ' + crear.map(c => c.fields.handle).join(', '));
return [{ json: { hay: crear.length > 0, crear, marcar } }];

// Armar plan de descubrimiento (ADR-020) — semillas rankeadas por señal + set de dedup + knobs.
const recs = (n) => $(n).all().flatMap((it) => (it.json && it.json.records) || []);
const _nrm = (s) => (s || '').toString().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/\s+/g, ' ').trim();
const cfg0 = $('Config').first().json;
// Knobs del equipo (Ajustes) sobre defaults de Config; caps de costo solo en Config (patrón ADR-011/016).
const AJUSTE_MAP = { 'propuestas por corrida': 'propuestas_max', 'afinidad minima de propuesta': 'afinidad_minima' };
const ajustes = {};
recs('Leer Ajustes').forEach(a => { const f = a.fields || {}; const k = AJUSTE_MAP[_nrm(f.clave)]; if (k && f.valor !== undefined && f.valor !== null && f.valor !== '') ajustes[k] = Number(f.valor); });
const pick = (k, d) => (ajustes[k] != null ? ajustes[k] : (cfg0[k] != null ? Number(cfg0[k]) : d));
const propuestas_max = Math.max(1, Number(pick('propuestas_max', 10)));
const afinidad_minima = Number(pick('afinidad_minima', 0.6));
const cap_semillas = Math.max(1, Number(cfg0.cap_semillas || 8));
const cap_detalle = Math.max(1, Number(cfg0.cap_perfiles_detalle || 20));

// Proyectos activos con criterios Proyecto ⊕ Voz (mismo modelo que el gate del motor, ADR-010).
const voces = {};
recs('Leer Voces').forEach(v => { const f = v.fields || {}; voces[v.id] = (f.criterios_relevancia || '').toString().trim(); });
const projects = {};
recs('Leer Proyectos').forEach(p => { const f = p.fields || {};
  const vozId = Array.isArray(f.voz_default) && f.voz_default[0] ? f.voz_default[0] : null;
  projects[p.id] = { id: p.id, nombre: f.nombre || '', criterios: (f.criterios_relevancia || '').toString().trim(), voz_criterios: (vozId && voces[vozId]) || '' };
});

// Dedup: cualquier handle ya conocido no se re-propone (Referentes activo o no + Propuestos en cualquier estado).
const conocidos = new Set();
const referentes = recs('Leer Referentes');
referentes.forEach(r => { const h = String(((r.fields || {}).handle) || '').trim().replace(/^@+/, '').toLowerCase(); if (h) conocidos.add(h); });
recs('Leer Propuestos').forEach(r => { const h = String(((r.fields || {}).handle) || '').trim().replace(/^@+/, '').toLowerCase(); if (h) conocidos.add(h); });

// Semillas: referentes IG activos de proyectos activos, rankeados por tasa de selección (fail-open sin señal).
const senal = {};
$('Leer señal selección').all().forEach(it => { const s = it.json || {}; if (s.referente) senal[String(s.referente).toLowerCase()] = { tasa: Number(s.tasa_seleccion || 0), cal: Number(s.calificados || 0) }; });
const semMap = {};
referentes.forEach(r => { const f = r.fields || {};
  if (!f.activo) return;
  if (String(f.plataforma || '').toLowerCase().indexOf('insta') < 0) return; // v1 solo IG (ADR-020)
  const h = String(f.handle || '').trim().replace(/^@+/, ''); if (!h) return;
  const proys = (Array.isArray(f.proyecto) ? f.proyecto : []).filter(id => projects[id]); if (!proys.length) return;
  const k = h.toLowerCase();
  (semMap[k] = semMap[k] || { handle: h, proyectos: new Set() });
  proys.forEach(id => semMap[k].proyectos.add(id));
});
const semillas = Object.entries(semMap)
  .map(([k, v]) => ({ handle: v.handle, proyectos: [...v.proyectos], tasa: (senal[k] || {}).tasa || 0, cal: (senal[k] || {}).cal || 0 }))
  .sort((a, b) => (b.tasa - a.tasa) || (b.cal - a.cal))
  .slice(0, cap_semillas);
const seed_to_proj = {};
semillas.forEach(s => { seed_to_proj[s.handle.toLowerCase()] = s.proyectos; });
console.log('[Descubrimiento] semillas (' + semillas.length + '): ' + semillas.map(s => s.handle + '(' + s.tasa.toFixed(2) + ')').join(', '));
return [{ json: { semillas: semillas.map(s => s.handle), seed_to_proj, conocidos: [...conocidos], projects, propuestas_max, afinidad_minima, cap_detalle } }];

// Agregar sugeridos — junta relatedProfiles de todas las semillas, dedup y rankea por frecuencia
// (sugerido por N semillas > sugerido por 1). Corta a cap_perfiles_detalle antes de pagar el detalle.
const plan = $('Armar plan de descubrimiento').first().json;
const conocidos = new Set(plan.conocidos || []);
const seedToProj = plan.seed_to_proj || {};
const cand = {};
for (const it of $input.all()) {
  const d = it.json || {};
  const seed = String(d.username || '').toLowerCase();
  const proys = seedToProj[seed] || [];
  for (const rp of (Array.isArray(d.relatedProfiles) ? d.relatedProfiles : [])) {
    const u = String((rp && rp.username) || '').trim().replace(/^@+/, ''); if (!u) continue;
    if (rp.is_private) continue;
    const k = u.toLowerCase(); if (conocidos.has(k)) continue;
    const c = (cand[k] = cand[k] || { username: u, freq: 0, proyectos: new Set(), semillas: new Set() });
    c.freq++; proys.forEach(p => c.proyectos.add(p)); if (seed) c.semillas.add(seed);
  }
}
const top = Object.values(cand).sort((a, b) => b.freq - a.freq).slice(0, Number(plan.cap_detalle || 20));
const candidatos = {};
top.forEach(c => { candidatos[c.username.toLowerCase()] = { username: c.username, freq: c.freq, proyectos: [...c.proyectos], semillas: [...c.semillas] }; });
console.log('[Descubrimiento] sugeridos únicos nuevos: ' + Object.keys(cand).length + ' → pasan a detalle: ' + top.length);
return [{ json: { usernames: top.map(c => c.username), candidatos, unicos: Object.keys(cand).length } }];

// Vetting relevancia (Haiku) — jurado estricto sobre bio + captions de últimos posts, por proyecto
// reclamante (criterios Proyecto ⊕ Voz, ADR-010). FAIL-CLOSED (ADR-020): si Haiku falla o no hay
// criterios, NO se propone (el riesgo acá es inundar al equipo de ruido, no perder contenido).
const KEY = '<ANTHROPIC_API_KEY>';
const plan = $('Armar plan de descubrimiento').first().json;
const projects = plan.projects || {};
const candidatos = ($('Agregar sugeridos').first().json || {}).candidatos || {};
const sleep = (ms) => new Promise(r => setTimeout(r, ms));

const detalle = {};
for (const it of $input.all()) {
  const d = it.json || {};
  const u = String(d.username || '').toLowerCase(); if (!u || !candidatos[u]) continue;
  if (d.private) continue;
  const caps = (Array.isArray(d.latestPosts) ? d.latestPosts : [])
    .map(p => String((p && p.caption) || '').replace(/\s+/g, ' ').trim()).filter(Boolean)
    .slice(0, 8).map(c => c.slice(0, 180));
  detalle[u] = { username: d.username, bio: String(d.biography || '').trim(), seguidores: Number(d.followersCount || 0), caps, url: String(d.url || ('https://www.instagram.com/' + d.username + '/')) };
}

const porProy = {};
Object.values(candidatos).forEach(c => { const u = c.username.toLowerCase(); if (!detalle[u]) return;
  c.proyectos.forEach(pid => { if (!projects[pid]) return; (porProy[pid] = porProy[pid] || []).push(u); });
});

const juicio = {}; // username → { afin, razon, proyectos }
let first = true;
for (const pid in porProy) {
  const p = projects[pid];
  const criterios = [p.criterios ? 'CRITERIOS DE TEMA (principal):\n' + p.criterios : '', p.voz_criterios ? 'AJUSTE DE VOZ (complementa, no manda):\n' + p.voz_criterios : ''].filter(Boolean).join('\n\n');
  if (!criterios) { console.log('[Vetting] proyecto sin criterios, se salta (fail-closed): ' + p.nombre); continue; }
  const lote = porProy[pid].map(u => { const d = detalle[u]; return { id: d.username, bio: d.bio.slice(0, 300), posts: d.caps.join(' | ').slice(0, 1200), seguidores: d.seguidores }; });
  if (!lote.length) continue;
  if (!first) await sleep(1000); first = false;
  const sys = 'Sos un jurado ESTRICTO que evalua CUENTAS de Instagram como posibles referentes de contenido para un proyecto. Te doy el tema del proyecto, sus criterios, y una lista de cuentas (id + bio + captions de sus ultimos posts). Para cada cuenta decidi que tan AFIN es el contenido que publica a los criterios (importa lo que publica, no su fama). Precision: ante la duda, score bajo. Devolve UNICAMENTE un JSON {"juicio":[{"id":"...","afin":0.0,"razon":"breve, en espanol"}]}. afin 0..1.';
  const usr = 'TEMA: ' + (p.nombre || '') + '\n' + criterios + '\n\nCUENTAS:\n' + JSON.stringify(lote);
  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST', url: 'https://api.anthropic.com/v1/messages',
      headers: { 'x-api-key': KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
      body: { model: 'claude-haiku-4-5', max_tokens: 4000, system: sys, messages: [{ role: 'user', content: usr }] },
      json: true, timeout: 60000
    });
    let txt = ''; (resp.content || []).forEach(b => { if (b && b.type === 'text') txt += b.text; });
    const m = txt.match(/\{[\s\S]*\}/);
    const j = m ? JSON.parse(m[0]) : null;
    ((j && j.juicio) || []).forEach(x => {
      const u = String(x.id || '').toLowerCase(); if (!detalle[u]) return;
      const afin = Math.max(0, Math.min(1, Number(x.afin || 0)));
      const prev = juicio[u];
      if (!prev) juicio[u] = { afin, razon: String(x.razon || ''), proyectos: [pid] };
      else { if (afin > prev.afin) { prev.afin = afin; prev.razon = String(x.razon || ''); } if (prev.proyectos.indexOf(pid) < 0) prev.proyectos.push(pid); }
    });
  } catch (e) { console.log('[Vetting] Haiku falló para ' + p.nombre + ' — FAIL-CLOSED, no se propone nada de este lote: ' + (e.message || e)); }
}

const out = [];
for (const u in juicio) { const d = detalle[u]; const c = candidatos[u];
  out.push({ json: { username: d.username, afin: juicio[u].afin, razon: juicio[u].razon, proyectos: juicio[u].proyectos, seguidores: d.seguidores, bio: d.bio, url: d.url, semillas: (c.semillas || []).join(', '), freq: c.freq || 1 } });
}
console.log('[Vetting] cuentas juzgadas con score: ' + out.length);
if (!out.length) return [{ json: { _vacio: true } }]; // la cadena sigue hasta Cerrar run
return out;

// Armar propuestas — umbral de afinidad + cap por corrida (Ajustes) → batches de 10 para Airtable.
const plan = $('Armar plan de descubrimiento').first().json;
const MIN = Number(plan.afinidad_minima || 0.6);
const MAX = Math.max(1, Number(plan.propuestas_max || 10));
const items = $input.all().map(i => i.json).filter(d => d && d.username && !d._vacio);
const elegidos = items.filter(d => Number(d.afin || 0) >= MIN)
  .sort((a, b) => (b.afin - a.afin) || ((b.freq || 0) - (a.freq || 0))).slice(0, MAX);
if (!elegidos.length) { console.log('[Descubrimiento] 0 propuestas sobre el umbral ' + MIN); return [{ json: { hay_propuestas: false, propuestos: 0 } }]; }
const records = elegidos.map(d => ({ fields: {
  handle: '@' + d.username, plataforma: 'instagram', proyecto: d.proyectos || [],
  afinidad: Math.round(Number(d.afin) * 100) / 100, razon: String(d.razon || '').slice(0, 500),
  seguidores: Number(d.seguidores || 0), bio: String(d.bio || '').slice(0, 500), url: d.url,
  semillas: d.semillas || '', estado: 'propuesto'
} }));
console.log('[Descubrimiento] proponiendo ' + records.length + ': ' + elegidos.map(d => d.username + '(' + d.afin + ')').join(', '));
const out = [];
for (let i = 0; i < records.length; i += 10) out.push({ json: { hay_propuestas: true, records: records.slice(i, i + 10), propuestos: records.length } });
return out;

