={{ (function(){
var g = function(n, f){ try { return f($(n)); } catch (e) { return null; } };
var plan = g('Armar plan de descubrimiento', function(x){ return x.first().json; }) || {};
var ag = g('Agregar sugeridos', function(x){ return x.first().json; }) || {};
var vet = g('Vetting relevancia (Haiku)', function(x){ return x.all().map(function(i){ return i.json; }).filter(function(d){ return d && d.username; }); }) || [];
var ap = g('Armar propuestas', function(x){ return x.first().json; }) || {};
var prom = g('Preparar promoción', function(x){ return x.first().json; }) || {};
return { fin: $now.toISO(), estado: 'ok', metricas: { semillas: (plan.semillas || []).length, sugeridos_unicos: ag.unicos || 0, detalle: (ag.usernames || []).length, vetteados: vet.length, propuestos: ap.propuestos || 0, promovidos: (prom.crear || []).length } };
})() }}
